mapper.select:
SELECT cm.COMMUNITY_ID, c.TENANT_ID, cm.USER_ID, cm.ROLE_CD, cm.STATUS_CD, cm.CRT_DT, cm.LAST_CHG_DT, u.USER_NM, u.USER_EMAIL, d.DEPT_NM, j.JBGD_NM, fd.FILE_PATH FROM COMMUNITY_MEMBER cm JOIN COMMUNITY c ON c.COMMUNITY_ID = cm.COMMUNITY_ID JOIN USERS u ON u.USER_ID = cm.USER_ID LEFT JOIN DEPARTMENT d ON d.DEPT_ID = u.DEPT_ID LEFT JOIN JOB_GRADE j ON j.JBGD_CD = u.JBGD_CD LEFT JOIN FILE_DETAIL fd ON fd.FILE_ID = u.USER_IMG_FILE_ID AND COALESCE(fd.DEL_YN, 'N') = 'N' WHERE c.TENANT_ID = #{tenantId} AND cm.COMMUNITY_ID = #{communityId}
AND cm.STATUS_CD = #{statusCd}
ORDER BY CASE cm.ROLE_CD WHEN 'owner' THEN 0 WHEN 'operator' THEN 1 ELSE 2 END, CASE cm.STATUS_CD WHEN 'active' THEN 0 WHEN 'pending' THEN 1 WHEN 'invited' THEN 2 ELSE 3 END, u.USER_NM

mapper.update:
UPDATE COMMUNITY_MEMBER
SET STATUS_CD = 'left',
    LAST_CHG_DT = CURRENT_TIMESTAMP
WHERE COMMUNITY_ID = #{communityId}
  AND USER_ID = #{userId}

mapper.select:
SELECT EXISTS (
    SELECT 1
    FROM COMMUNITY_MEMBER cm
    JOIN COMMUNITY c
      ON c.COMMUNITY_ID = cm.COMMUNITY_ID
    WHERE c.TENANT_ID = #{tenantId}
      AND cm.COMMUNITY_ID = #{communityId}
      AND cm.USER_ID = #{userId}
      AND cm.STATUS_CD = 'active'
)
